  it('rejects malformed input via Zod before invoking spawnImpl', async () => {
    const bus = new HookBus();
    await createSandboxSubprocessPlugin().init({ bus, config: {} });
    await expect(
      bus.call('sandbox:spawn', ctx(), { argv: [], cwd: '/tmp', env: {} }),
