```ts
import { z } from 'zod';
import type {
  Plugin,
  SandboxSpawnInput,
  SandboxSpawnResult,
} from '@ax/core';

const PLUGIN_NAME = '@ax/tool-bash';

const BashInputSchema = z.object({
  command: z.string().min(1).max(16_384),
  timeoutMs: z.number().int().positive().max(300_000).optional(),
});

export function createToolBashPlugin(): Plugin {
  return {
    manifest: {
      name: PLUGIN_NAME,
      version: '0.0.0',
      registers: ['tool:execute:bash'],
      calls: ['sandbox:spawn'],
      subscribes: [],
    },
    async init({ bus }) {
      bus.registerService(
        'tool:execute:bash',
        PLUGIN_NAME,
        async (ctx, raw) => {
          const parsed = BashInputSchema.parse(raw);
          const spawned = await bus.call<SandboxSpawnInput, SandboxSpawnResult>(
            'sandbox:spawn',
            ctx,
            {
              argv: ['/bin/bash', '-c', parsed.command],
              cwd: ctx.workspace.rootPath,
              env: {},
              timeoutMs: parsed.timeoutMs ?? 30_000,
            },
          );
          return {
            stdout: spawned.stdout,
            stderr: spawned.stderr,
            exitCode: spawned.exitCode,
            timedOut: spawned.timedOut,
            truncated: spawned.truncated,
          };
        },
      );
    },
  };
}
```

