  });

  it('descriptor input schema names command and timeoutMs', () => {
    expect(bashToolDescriptor.name).toBe('bash');
    expect(bashToolDescriptor.inputSchema.required).toContain('command');
  });

  it('delegates to sandbox:spawn with /bin/bash -c <command>, env:{}, cwd=workspace.rootPath', async () => {
    const bus = new HookBus();
    const spy = vi.fn(async (_c: unknown, i: SandboxSpawnInput): Promise<SandboxSpawnResult> => ({
      exitCode: 0, signal: null, stdout: 'ran', stderr: '',
      truncated: { stdout: false, stderr: false }, timedOut: false,
    }));
    bus.registerService('sandbox:spawn', 'fake-sandbox', spy);
    await createToolBashPlugin().init({ bus, config: {} });

    const r = await bus.call('tool:execute:bash', ctx('/tmp/ws'), { command: 'echo hi' });
    expect(r).toMatchObject({ stdout: 'ran', stderr: '', exitCode: 0, timedOut: false });

