    const bus = new HookBus();
    const spy = vi.fn();
    bus.registerService('sandbox:spawn', 'fake', spy);
    await createToolBashPlugin().init({ bus, config: {} });
    await expect(
      bus.call('tool:execute:bash', ctx('/tmp'), { command: 'x'.repeat(16_385) }),
    ).rejects.toThrow();
    expect(spy).not.toHaveBeenCalled();
  });

