**Schema:**

```ts
import { z } from 'zod';

export const AxConfigSchema = z.object({
  llm: z.enum(['anthropic', 'mock']).default('mock'),
  sandbox: z.enum(['subprocess']).default('subprocess'),
  tools: z.array(z.enum(['bash', 'file-io'])).default(['bash', 'file-io']),
  storage: z.enum(['sqlite']).default('sqlite'),
  anthropic: z.object({
    model: z.string().optional(),
    maxTokens: z.number().int().positive().optional(),
  }).optional(),
}).strict();

export type AxConfigInput = z.input<typeof AxConfigSchema>;
export type AxConfig = z.output<typeof AxConfigSchema>;
```

Note the `.strict()` — unknown keys rejected. Because `z.infer` gives the `z.output` shape (defaulted fields required) but callers pass fewer fields (defaulted-field optional), export BOTH `AxConfigInput` (for callers / config-file authors) and `AxConfig` (for internal use after parse).

