**Loader:**

```ts
import { pathToFileURL } from 'node:url';
import * as fs from 'node:fs/promises';
import * as path from 'node:path';
import { AxConfigSchema, type AxConfig } from './schema.js';

const CANDIDATES = ['ax.config.ts', 'ax.config.js', 'ax.config.mjs'];

export interface LoadOptions {
  cwd?: string;           // defaults to process.cwd()
  explicitPath?: string;  // if set, only that path is attempted
}

export async function loadAxConfig(opts: LoadOptions = {}): Promise<AxConfig> {
  const cwd = opts.cwd ?? process.cwd();

  if (opts.explicitPath) {
    return await loadFromFile(path.resolve(cwd, opts.explicitPath));
  }

  for (const candidate of CANDIDATES) {
    const abs = path.resolve(cwd, candidate);
    try {
      await fs.access(abs);
      return await loadFromFile(abs);
    } catch {
      continue;
    }
  }
  // Nothing found: use schema defaults.
  return AxConfigSchema.parse({});
}

async function loadFromFile(abs: string): Promise<AxConfig> {
  const url = pathToFileURL(abs).href;
  const mod = await import(url);
  const candidate = (mod as { default?: unknown }).default;
  if (candidate === undefined) {
    throw new Error(`ax.config file at ${abs} has no default export`);
  }
  const parsed = AxConfigSchema.safeParse(candidate);
  if (!parsed.success) {
    throw new Error(`ax.config at ${abs} failed validation:\n${parsed.error.message}`);
  }
  return parsed.data;
}
```

Note: loading an `ax.config.ts` file via `import()` requires the host to have a TS loader (tsx, ts-node). For Week 4-6, the CLI binary runs built JS and accepts `.ts` source at load-time only if `--import=tsx/esm` is set. The library-mode `main()` can accept a `configOverride` to bypass file loading entirely — that's how Phase 8 tests will work. For the real-user case with `ax.config.ts`, document the `--import tsx/esm` requirement in the main.ts shebang path (future improvement, not this task).

