import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import * as path from 'node:path';
import * as fs from 'node:fs/promises';
import * as os from 'node:os';
import BetterSqlite3 from 'better-sqlite3';

// Mock the SDK BEFORE importing main (and therefore before the plugin's module
// loads). `vi.hoisted` ensures the mock factory sees `responsesRef` declared
// below; vitest rewrites the import order so the mock is installed first.
