    // Turn 1: model asks to run `bash -c "echo hello"`.
    responsesRef.responses.push({
      content: [
        { type: 'tool_use', id: 't1', name: 'bash', input: { command: 'echo hello' } },
      ],
      stop_reason: 'tool_use',
    });
    // Turn 2: model sees the tool result and emits a text message.
    responsesRef.responses.push({
      content: [{ type: 'text', text: 'done' }],
      stop_reason: 'end_turn',
    });

    const lines: string[] = [];
    const sqlitePath = path.join(tmp, 'e2e.sqlite');

    const code = await main({
      message: 'list files',
      configOverride: {
        llm: 'anthropic',
        tools: ['bash'],        // tool-file-io not needed for this test
        sandbox: 'subprocess',
        storage: 'sqlite',
